            Thread thread = new Thread(() -> {
                try {
                    runnable.run();
                } finally {
                    ThreadBridge.clear();
                }
            });
            thread.setName("textd-worker-" + sequence.getAndIncrement());
            thread.setDaemon(true);
            return thread;
        }
    }
